import java.util.*;

public class Q1 {
    static boolean matchesType(String val, String type) {
        return switch (type) {
            case "INTEGER" -> val.matches("-?[0-9]+");
            case "BOOLEAN" -> val.equals("true") || val.equals("false");
            case "STRING"  -> val != null && !val.isEmpty();
            default -> false;
        };
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int c = sc.nextInt(); sc.nextLine();
        Map<String, String> contract = new LinkedHashMap<>();
        for (int i = 0; i < c; i++) {
            String[] p = sc.nextLine().trim().split(" ");
            contract.put(p[0], p[1]);
        }
        int n = sc.nextInt(); sc.nextLine();
        for (int i = 0; i < n; i++) {
            Map<String, String> resp = new HashMap<>();
            for (String kv : sc.nextLine().trim().split(" ")) {
                String[] p = kv.split("=", 2);
                resp.put(p[0], p[1]);
            }
            String result = "VALID";
            for (Map.Entry<String, String> e : contract.entrySet()) {
                String field = e.getKey(), type = e.getValue();
                if (!resp.containsKey(field)) { result = "INVALID: missing " + field; break; }
                if (!matchesType(resp.get(field), type)) { result = "INVALID: wrong type " + field; break; }
            }
            System.out.println(result);
        }
    }
}

