        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt(); sc.nextLine();
        Map<String, String> oldC = new LinkedHashMap<>();
        for (int i = 0; i < n; i++) { String[] p = sc.nextLine().trim().split(" "); oldC.put(p[0], p[1]); }
        int m = sc.nextInt(); sc.nextLine();
        Map<String, String> newC = new HashMap<>();
        for (int i = 0; i < m; i++) { String[] p = sc.nextLine().trim().split(" "); newC.put(p[0], p[1]); }
        List<String> issues = new ArrayList<>();
        for (Map.Entry<String, String> e : oldC.entrySet()) {
            String field = e.getKey(), oldType = e.getValue();
            if (!newC.containsKey(field)) issues.add("REMOVED: " + field);
            else if (!newC.get(field).equals(oldType)) issues.add("TYPE_CHANGED: " + field);
        }
        if (issues.isEmpty()) System.out.println("NO_BREAKING_CHANGES");
        else issues.forEach(System.out::println);
    }
}

