import java.util.*;

public class Q3 {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt(); sc.nextLine();
        Map<String, List<String>> states = new LinkedHashMap<>();
        for (int i = 0; i < n; i++) {
            String line = sc.nextLine().trim();
            String[] p = line.split(":", 2);
            String state = p[0];
            List<String> steps = (p.length > 1 && !p[1].isEmpty())
                ? Arrays.asList(p[1].split(",")) : List.of();
            states.put(state, steps);
        }
        int m = sc.nextInt(); sc.nextLine();
        Set<String> seen = new LinkedHashSet<>();
        for (int i = 0; i < m; i++) {
            String state = sc.nextLine().trim();
            seen.addAll(states.getOrDefault(state, List.of()));
        }
        seen.forEach(System.out::println);
    }
}

